// ดThe current temperature is sent directly from Helsinki, Finland.
var currentTemp = msg.payload.current.temperature_2m;

// Create a new dataset for our IoT Automation system.
msg.payload = {
    location: "Helsinki Data Center Node (Finland)",
    temperature: currentTemp,
    unit: "Celsius",
    timestamp: new Date().toISOString()
};

// Automatic Electrical/Air Conditioning Control Logic (Automation Logic)
// Assume that if the server room temperature in Finland exceeds 20 degrees Celsius, the system should send an alert.
if (currentTemp > 20.0) {
    msg.payload.cooling_status = "❌ ALERT: Temperature High! Activating Emergency Fans.";
    msg.payload.system_integrity = "WARNING";
} else {
    msg.payload.cooling_status = "✅ NORMAL: Safe Operating Temperature.";
    msg.payload.system_integrity = "STABLE";
}
msg.payload = currentTemp; // ส่งเฉพาะตัวเลขอุณหภูมิเพียวๆ ออกไปให้ Dashboard
return msg;
